83: void AdminFilter::onComplete() {
84:   absl::string_view path = request_headers_->getPathValue();
85:   ENVOY_STREAM_LOG(debug, "request complete: path: {}", *decoder_callbacks_, path);
86: 
87:   auto header_map = Http::ResponseHeaderMapImpl::create();
88:   RELEASE_ASSERT(request_headers_, "");
89:   Admin::RequestPtr handler = admin_.makeRequest(*this);
90:   Http::Code code = handler->start(*header_map);
91:   Utility::populateFallbackResponseHeaders(code, *header_map);
92:   decoder_callbacks_->encodeHeaders(std::move(header_map), false,
93:                                     StreamInfo::ResponseCodeDetails::get().AdminFilterResponse);
94: 
95:   // TODO(#31087): use high/lower watermarks to apply flow-control to the admin http port.
96:   bool more_data;
97:   do {
98:     Buffer::OwnedImpl response;
99:     more_data = handler->nextChunk(response);
100:     bool end_stream = end_stream_on_complete_ && !more_data;
101:     ENVOY_LOG_MISC(debug, "nextChunk: response.length={} more_data={} end_stream={}",
102:                    response.length(), more_data, end_stream);
103:     if (response.length() > 0 || end_stream) {
104:       decoder_callbacks_->encodeData(response, end_stream);
105:     }
106:   } while (more_data);
107: }
